def solve(data):
    bytes_to_process = 0
    for num in data:
        if bytes_to_process == 0:
            if (num >> 7) == 0:
                continue
            elif (num >> 5) == 0b110:
                bytes_to_process = 1
            elif (num >> 4) == 0b1110:
                bytes_to_process = 2
            elif (num >> 3) == 0b11110:
                bytes_to_process = 3
            else:
                return "false"
        else:
            if (num >> 6) != 0b10:
                return "false"
            bytes_to_process -= 1

    return "true" if bytes_to_process == 0 else "false"

